{
  "questions": [
    {
      "question": "Today, setting an external repo URL REPLACES in-portal code pages (citations link straight to GitHub, no in-portal page). You seem to want in-portal browsing kept AND a link out. Which behavior should the new story establish?",
      "header": "Link model",
      "multiSelect": false,
      "options": [
        {
          "label": "Additive 'View on GitHub'",
          "description": "Always generate the in-portal (graph-focused) page; add a 'View source on GitHub ↗' link to the hosted file. In-portal browsing is never replaced."
        },
        {
          "label": "Keep replacement, add detection",
          "description": "Preserve current behavior (external URL skips in-portal pages); the new story only adds auto-detection of the base URL."
        },
        {
          "label": "Configurable both ways",
          "description": "Support both modes via a flag: additive by default, opt-in full replacement for those who want an external-only site."
        }
      ]
    },
    {
      "question": "For the redesigned code page, what does the 'graph / what-refers-to-what' view actually look like? (Note: current data is artifact→file only — stories cite files; there is no file→file citation graph.)",
      "header": "Graph view",
      "multiSelect": false,
      "options": [
        {
          "label": "Structured relationships panel",
          "description": "Referenced-by grouped by epic/story/requirement type, elevated to the top; raw code collapsed or de-emphasized below. Pure HTML/CSS."
        },
        {
          "label": "Visual node-link SVG graph",
          "description": "An SVG graph with this file at the center connected to citing stories/epics (consistent with the project's pure-SVG, no-JS charting)."
        },
        {
          "label": "Both panel + SVG graph",
          "description": "Structured relationships panel plus a small visual node-link graph. More build, richest view."
        }
      ]
    },
    {
      "question": "How should SpecScribe figure out the external base URL when you don't pass one explicitly?",
      "header": "URL detection",
      "multiSelect": false,
      "options": [
        {
          "label": "Git remote + Pages detect",
          "description": "Parse git remote origin (GitHub/GitLab → blob URL) AND detect GitHub Pages/CI deployment context; explicit --code-url always overrides."
        },
        {
          "label": "Git remote only",
          "description": "Auto-derive from git remote origin URL; explicit --code-url overrides. Skip Pages-specific detection."
        },
        {
          "label": "Manual config only",
          "description": "No auto-detection; just add interactive-menu parity for the existing CLI-only --code-url setting."
        }
      ]
    },
    {
      "question": "How should this work be split into BMad stories? (Story 7.1 is currently in 'review'.)",
      "header": "Story split",
      "multiSelect": false,
      "options": [
        {
          "label": "Two new stories (7.7 + 7.8)",
          "description": "7.7 = code-page UX/graph redesign; 7.8 = external-source linking + auto-detection. Leaves 7.1 as-shipped."
        },
        {
          "label": "One new story (7.7)",
          "description": "Single new story covering both the UX/graph redesign and external-source linking/detection."
        },
        {
          "label": "Reopen 7.1 + new 7.7",
          "description": "Reopen Story 7.1 for the UX/graph redesign (it owns the code page); new 7.7 for external linking + detection."
        }
      ]
    }
  ]
}

