1	using System.Globalization;
2	using System.Text;
3	
4	namespace SpecScribe;
5	
6	/// <summary>Renders one in-portal code file page (Story 7.1) — a line-numbered, HTML-escaped, monospace view of a
7	/// referenced repository source file at <c>code/&lt;repo-relative-path&gt;.html</c>. A synthesized page (no markdown
8	/// source), so it builds its own shell via <see cref="PathUtil.RenderHeadOpen"/> the way
9	/// <see cref="CommitDayTemplater"/> does rather than going through <see cref="HtmlTemplater.RenderPage"/>.
10	///
11	/// Every line gets a stable <c>id="L{n}"</c> anchor (1-based, GitHub-compatible) so citations rewritten in Story 7.2
12	/// can deep-link to <c>code/&lt;path&gt;.html#L42</c>; that anchor scheme is a locked cross-story convention. No
13	/// syntax highlighter and no client JS: "syntax-readable" here means legible-as-code (monospace, line numbers,
14	/// preserved whitespace, horizontal scroll for long lines), not tokenized coloring.</summary>
15	public static class CodeFileTemplater
16	{
17	    /// <summary>Renders the full code page. <paramref name="lines"/> is rendered verbatim — one anchored
18	    /// <c>.code-line</c> per element, numbered from 1, including blank lines — so line numbers stay 1:1 with the
19	    /// source. The caller owns newline normalization and escaping is applied here. <paramref name="referencedBy"/>
20	    /// (Story 7.2, AC #2) is the set of artifacts that cite this file, each an output-relative URL + display title;
21	    /// an empty list omits the "Referenced by" block entirely (no empty heading).</summary>
22	    public static string RenderPage(
23	        string repoRelativePath,
24	        string outputRelativePath,
25	        IReadOnlyList<string> lines,
26	        SiteNav nav,
27	        IReadOnlyList<(string OutputUrl, string Title)>? referencedBy = null)
28	    {
29	        var prefix = PathUtil.RelativePrefix(outputRelativePath);
30	        var sb = BeginShell(repoRelativePath, outputRelativePath, prefix, nav);
31	
32	        var count = lines.Count;
33	        sb.Append($"  <div class=\"meta-pills\"><span class=\"pill\">{count.ToString(CultureInfo.InvariantCulture)} {(count == 1 ? "line" : "lines")}</span></div>\n");
34	        sb.Append("</header>\n\n");
35	
36	        AppendReferencedBy(sb, prefix, referencedBy);
37	
38	        sb.Append("<pre class=\"code-file\"><code>");
39	        for (var i = 0; i < count; i++)
40	        {
41	            var n = i + 1;
42	            sb.Append($"<span class=\"code-line\" id=\"L{n.ToString(CultureInfo.InvariantCulture)}\">")
43	              .Append($"<span class=\"code-ln\">{n.ToString(CultureInfo.InvariantCulture)}</span>")
44	              .Append($"<span class=\"code-src\">{PathUtil.Html(lines[i])}</span></span>\n");
45	        }
46	        sb.Append("</code></pre>\n\n");
47	
48	        return EndShell(sb, prefix);
49	    }
50	
51	    /// <summary>Emits the "Referenced by" back-navigation block (Story 7.2, AC #2): a semantic list of the artifacts
52	    /// that cite this file, inside the existing <c>&lt;main&gt;</c> landmark with meaningful link text (the citing
53	    /// artifact's title, never "click here" — NFR6/UX-DR16). Neutral <c>--ink</c>/<c>--border</c>/<c>--parchment</c>
54	    /// tokens only. An empty list writes nothing (no bare heading).</summary>
55	    private static void AppendReferencedBy(StringBuilder sb, string prefix, IReadOnlyList<(string OutputUrl, string Title)>? referencedBy)
56	    {
57	        if (referencedBy is null || referencedBy.Count == 0) return;
58	
59	        sb.Append("<aside class=\"code-referenced-by\">\n");
60	        sb.Append("  <h2>Referenced by</h2>\n");
61	        sb.Append("  <ul>\n");
62	        foreach (var (outputUrl, title) in referencedBy)
63	        {
64	            var href = PathUtil.Html(prefix + PathUtil.NormalizeSlashes(outputUrl));
65	            sb.Append($"    <li><a href=\"{href}\">{PathUtil.Html(title)}</a></li>\n");
66	        }
67	        sb.Append("  </ul>\n");
68	        sb.Append("</aside>\n\n");
69	    }
70	
71	
72	    /// <summary>Renders a clearly-marked placeholder page for a referenced file that exists but can't be shown
73	    /// inline (binary, oversized, or unreadable). The page still carries the full nav/breadcrumb/a11y shell and a
74	    /// stable URL so navigation never breaks (AC #1) — only the line table is replaced by an explanatory note.</summary>
75	    public static string RenderPlaceholder(
76	        string repoRelativePath,
77	        string outputRelativePath,
78	        string reason,
79	        SiteNav nav)
80	    {
81	        var prefix = PathUtil.RelativePrefix(outputRelativePath);
82	        var sb = BeginShell(repoRelativePath, outputRelativePath, prefix, nav);
83	
84	        sb.Append("  <div class=\"meta-pills\"><span class=\"pill\">Not rendered</span></div>\n");
85	        sb.Append("</header>\n\n");
86	        sb.Append($"<p class=\"code-placeholder\">{PathUtil.Html(reason)}</p>\n\n");
87	
88	        return EndShell(sb, prefix);
89	    }
90	
91	    /// <summary>Emits the head + nav + breadcrumb + open <c>&lt;main&gt;</c>/<c>&lt;header&gt;</c> shared by both the
92	    /// full page and the placeholder. Leaves the header open so each caller appends its own meta pill(s) and closes
93	    /// it — mirroring the synthesized-page shape of <see cref="CommitDayTemplater"/>.</summary>
94	    private static StringBuilder BeginShell(string repoRelativePath, string outputRelativePath, string prefix, SiteNav nav)
95	    {
96	        var sb = new StringBuilder();
97	        sb.Append(PathUtil.RenderHeadOpen(
98	            $"{repoRelativePath} — {nav.SiteTitle}",
99	            prefix + ForgeOptions.StylesheetName,
100	            prefix + ForgeOptions.ScriptName,
101	            $"Source file {repoRelativePath} in {nav.SiteTitle}."));
102	        sb.Append(nav.RenderNavBar(outputRelativePath));
103	        sb.Append(SiteNav.RenderBreadcrumb(outputRelativePath, new (string, string?)[]
104	        {
105	            ("Home", "index.html"),
106	            (repoRelativePath, null),
107	        }));
108	
109	        // Single <main id="main-content"> landmark / skip-link target. [Story 1.4 AC #1]
110	        sb.Append("<main id=\"main-content\">\n");
111	        sb.Append("<header class=\"doc-header\">\n");
112	        sb.Append("  <div class=\"story-kicker\">Source File</div>\n");
113	        sb.Append($"  <h1>{PathUtil.Html(repoRelativePath)}</h1>\n");
114	        return sb;
115	    }
116	
117	    private static string EndShell(StringBuilder sb, string prefix)
118	    {
119	        sb.Append("</main>\n\n");
120	        sb.Append(PathUtil.RenderFooter(prefix));
121	        sb.Append("</body>\n</html>\n");
122	        return sb.ToString();
123	    }
124	}
