1	using System.Globalization;
2	using System.Text.RegularExpressions;
3	
4	namespace SpecScribe;
5	
6	/// <summary>Resolves source-code citations left inert by Story 7.1 into real links to the in-portal code pages
7	/// (<c>code/&lt;repo-rel&gt;.html#L{n}</c>) — or, in external-link mode, to <c>{CodeSourceBaseUrl}/&lt;repo-rel&gt;#L{n}</c>
8	/// (Story 7.2, FR15). Runs as a whole-page post-process in <see cref="SiteGenerator.ApplyReferenceLinks"/> — the same
9	/// pass that already runs <see cref="RequirementLinkifier"/>/<see cref="StoryEpicLinkifier"/> on every generated page —
10	/// so a citation resolves no matter which template emitted it and no matter whether it sits in body prose or inside a
11	/// rendered markdown comment (<c>&lt;aside class="md-comment"&gt;</c>, Story 2.6 — the "comment linking" half of the story).
12	///
13	/// Two matchers share one resolver, mirroring the two real citation shapes:
14	/// <list type="number">
15	/// <item><b>Href rewriter</b> (models <see cref="AdrLinkRewriter"/>): the Markdig-emitted <c>&lt;a href="…/src/…(:line)?"&gt;</c>
16	/// "view-source" links. The line number is read from the <c>:N</c> href suffix; unresolved links have their anchor
17	/// dropped so only plain text remains (AC #1 — never a broken link).</item>
18	/// <item><b>Anchor-aware plain-text matcher</b> (models <see cref="RequirementLinkifier"/>): inert
19	/// <c>[Source: `src/…`]</c> / <c>[Source: src/…]</c> code-span citations that never became links, including inside
20	/// comment asides. Split on <c>&lt;a&gt;…&lt;/a&gt;</c> so an already-produced link is never re-wrapped.</item>
21	/// </list>
22	///
23	/// The <c>#L{n}</c> fragment is identical in both link modes — Story 7.1 locked that so this logic never branches on
24	/// the fragment. The <c>.md</c> citation path (<see cref="SourceLinkifier"/>) is deliberately untouched: this is a
25	/// PARALLEL resolver for repository code files, not a rewrite of doc-citation handling.</summary>
26	public static class CodeReferenceLinkifier
27	{
28	    // Any anchor; the evaluator decides whether its href is a resolvable code reference. Singleline so a label may
29	    // span lines. Attribute order is not assumed (href may sit anywhere in the tag).
30	    private static readonly Regex AnchorPattern = new(
31	        "<a\\b[^>]*?\\bhref=\"(?<href>[^\"]*)\"[^>]*>(?<label>.*?)</a>",
32	        RegexOptions.Compiled | RegexOptions.Singleline | RegexOptions.IgnoreCase);
33	
34	    // Splits out whole anchor spans so the plain-text matcher only rewrites the non-anchor segments (mirrors
35	    // RequirementLinkifier) — never re-linking the href rewriter's own output or any nav/req-ref link.
36	    private static readonly Regex AnchorSplit = new(
37	        "(<a\\b[^>]*>.*?</a>)",
38	        RegexOptions.Compiled | RegexOptions.Singleline | RegexOptions.IgnoreCase);
39	
40	    // Inert "[Source: <path>]" citation in plain text — optionally wrapped in a <code> span (a rendered code-span)
41	    // or literal backticks (the shape a citation keeps INSIDE an HTML-escaped comment aside). The path stops before
42	    // any '<' so it never swallows an adjacent tag. Mirrors CodeReferenceScanner.SourceInline over rendered HTML.
43	    private static readonly Regex InlineCitation = new(
44	        "\\[Source:\\s*(?<inner>(?:<code>)?`?(?<path>[^\\[\\]`)\\r\\n<]+?)`?(?:</code>)?)\\s*\\]",
45	        RegexOptions.Compiled | RegexOptions.IgnoreCase);
46	
47	    /// <summary>Rewrites both citation shapes on one rendered page.</summary>
48	    /// <param name="html">Already-rendered page HTML.</param>
49	    /// <param name="codePages">Story 7.1's forward map: repo-relative source path (forward slashes) → code-page
50	    /// output-relative path (<c>code/&lt;path&gt;.html</c>). Empty in external mode.</param>
51	    /// <param name="codeSourceBaseUrl">External-link base (<c>--code-url</c>) when set; null selects in-portal mode.</param>
52	    /// <param name="prefix">The page's climb back to the output root (<see cref="PathUtil.RelativePrefix"/>).</param>
53	    /// <param name="repoRoot">Repo root — for the external-mode "is this a real repo file?" gate.</param>
54	    /// <param name="sourceRoot">The <c>_bmad-output</c> source root — excluded from code resolution (doc pages already exist).</param>
55	    public static string Linkify(
56	        string html,
57	        IReadOnlyDictionary<string, string> codePages,
58	        string? codeSourceBaseUrl,
59	        string prefix,
60	        string repoRoot,
61	        string sourceRoot)
62	    {
63	        if (string.IsNullOrEmpty(html)) return html;
64	
65	        var external = codeSourceBaseUrl is { Length: > 0 };
66	        // No in-portal pages and no external base ⇒ nothing can resolve. Leave the page exactly as-is.
67	        if (!external && codePages.Count == 0) return html;
68	
69	        var baseUrl = external ? codeSourceBaseUrl!.TrimEnd('/') : null;
70	
71	        // Form A — rewrite/strip the view-source anchors first, then form B — the inert code-span/comment citations.
72	        html = RewriteHrefs(html, codePages, baseUrl, prefix, repoRoot, sourceRoot);
73	        html = RewriteInline(html, codePages, baseUrl, prefix, repoRoot, sourceRoot);
74	        return html;
75	    }
76	
77	    private static string RewriteHrefs(
78	        string html, IReadOnlyDictionary<string, string> codePages, string? baseUrl, string prefix, string repoRoot, string sourceRoot)
79	    {
80	        return AnchorPattern.Replace(html, m =>
81	        {
82	            var href = m.Groups["href"].Value;
83	            var label = m.Groups["label"].Value;
84	
85	            // Only relative, non-page hrefs are candidate view-source links. Absolute URLs, in-page fragments,
86	            // and already-generated .html/.md pages are left exactly as they are (the latter keeps this idempotent
87	            // and off SourceLinkifier/AdrLinkRewriter's turf).
88	            if (!IsRelativeCodeHref(href)) return m.Value;
89	
90	            var pathPart = CodeReferenceScanner.StripLocator(href, out var line);
91	            if (pathPart.Length == 0) return m.Value;
92	
93	            if (TryBuildHref(pathPart, line, codePages, baseUrl, prefix, repoRoot, sourceRoot, out var resolved))
94	            {
95	                return $"<a href=\"{PathUtil.Html(resolved)}\">{label}</a>";
96	            }
97	
98	            // Unresolved view-source link ⇒ drop the dead anchor, keep its text (AC #1). Never a broken link.
99	            return label;
100	        });
101	    }
102	
103	    private static string RewriteInline(
104	        string html, IReadOnlyDictionary<string, string> codePages, string? baseUrl, string prefix, string repoRoot, string sourceRoot)
105	    {
106	        var parts = AnchorSplit.Split(html);
107	        for (var i = 0; i < parts.Length; i++)
108	        {
109	            // Odd indices are the captured <a>…</a> spans — leave them untouched.
110	            if (i % 2 == 1) continue;
111	            parts[i] = InlineCitation.Replace(parts[i], m =>
112	            {
113	                var inner = m.Groups["inner"].Value;
114	                var rawPath = m.Groups["path"].Value.Trim();
115	                var pathPart = CodeReferenceScanner.StripLocator(rawPath, out var line);
116	                if (pathPart.Length == 0) return m.Value;
117	
118	                if (TryBuildHref(pathPart, line, codePages, baseUrl, prefix, repoRoot, sourceRoot, out var resolved))
119	                {
120	                    // Wrap the original inner text (code-span markup and locator preserved) so the citation still
121	                    // reads as written but is now clickable.
122	                    return $"[Source: <a href=\"{PathUtil.Html(resolved)}\">{inner}</a>]";
123	                }
124	
125	                // Unresolved ⇒ already plain text; leave it exactly as-is (AC #1).
126	                return m.Value;
127	            });
128	        }
129	        return string.Concat(parts);
130	    }
131	
132	    /// <summary>Resolves one citation path to a final href, or returns false to degrade it to plain text. In-portal
133	    /// mode gates strictly on membership in Story 7.1's page map (so a link can only ever point at a page that exists);
134	    /// external mode gates on the candidate resolving to a real, non-ignored repository file (so it never points at a
135	    /// path that isn't really in the repo). The <c>#L{n}</c> fragment is appended identically in both.</summary>
136	    private static bool TryBuildHref(
137	        string pathPart, int? line, IReadOnlyDictionary<string, string> codePages, string? baseUrl, string prefix,
138	        string repoRoot, string sourceRoot, out string href)
139	    {
140	        href = string.Empty;
141	        var fragment = line is { } n ? "#L" + n.ToString(CultureInfo.InvariantCulture) : string.Empty;
142	
143	        if (baseUrl is not null)
144	        {
145	            // External mode: reconstruct the repo-relative candidate (strip a view-source href's leading ../) and
146	            // confirm it is a real repository file before emitting an external link.
147	            var candidate = StripLeadingRelative(PathUtil.NormalizeSlashes(pathPart));
148	            if (candidate.Length == 0) return false;
149	            if (!CodeReferenceScanner.TryResolveRepoFile(candidate, repoRoot, sourceRoot, out var repoRel)) return false;
150	            href = baseUrl + "/" + repoRel + fragment;
151	            return true;
152	        }
153	
154	        // In-portal mode: the strip-leading-../ candidate must name a generated code page.
155	        var key = StripLeadingRelative(PathUtil.NormalizeSlashes(pathPart));
156	        if (key.Length == 0) return false;
157	        if (!codePages.TryGetValue(key, out var outputRelative)) return false;
158	        href = prefix + outputRelative + fragment;
159	        return true;
160	    }
161	
162	    /// <summary>True when an href is a relative reference to a NON-page file — the shape of a view-source code link.
163	    /// Absolute URLs (any scheme, protocol-relative, root- or fragment-relative) and generated <c>.html</c>/<c>.md</c>
164	    /// pages are excluded so this never touches nav, requirement, doc-citation, or ADR links.</summary>
165	    private static bool IsRelativeCodeHref(string href)
166	    {
167	        if (string.IsNullOrEmpty(href)) return false;
168	        if (href[0] is '#' or '/' or '?') return false;
169	        if (href.Contains("://", StringComparison.Ordinal)) return false;
170	        if (href.StartsWith("mailto:", StringComparison.OrdinalIgnoreCase)) return false;
171	
172	        var bare = CodeReferenceScanner.StripLocator(href);
173	        if (bare.Length == 0) return false;
174	        if (bare.EndsWith(".html", StringComparison.OrdinalIgnoreCase)) return false;
175	        if (bare.EndsWith(".md", StringComparison.OrdinalIgnoreCase)) return false;
176	
177	        // A code reference names a file: require an extension on the last path segment so extension-less relative
178	        // links (e.g. "../overview") are left alone.
179	        var lastSlash = bare.LastIndexOfAny(new[] { '/', '\\' });
180	        var lastSegment = lastSlash >= 0 ? bare[(lastSlash + 1)..] : bare;
181	        return lastSegment.Contains('.');
182	    }
183	
184	    /// <summary>Strips a run of leading <c>./</c> / <c>../</c> segments, recovering the repo-relative tail a
185	    /// well-formed view-source href climbs to. In-portal membership / external existence is the real gate, so an
186	    /// over-climbing href simply fails to resolve and degrades to plain text.</summary>
187	    private static string StripLeadingRelative(string path)
188	    {
189	        var i = 0;
190	        while (true)
191	        {
192	            if (path.AsSpan(i).StartsWith("../")) i += 3;
193	            else if (path.AsSpan(i).StartsWith("./")) i += 2;
194	            else break;
195	        }
196	        return path[i..];
197	    }
198	}
199

1	using System.Text.RegularExpressions;
2	
3	namespace SpecScribe;
4	
5	/// <summary>Resolved absolute paths and settings for a run.</summary>
6	public sealed class ForgeOptions
7	{
8	    public required string RepoRoot { get; init; }
9	    public required string SourceRoot { get; init; }
10	
11	    /// <summary>Hand-authored Architecture Decision Records (<c>docs/adrs</c>). A read-only second source: SpecScribe
12	    /// renders these into the live site but never writes back to this folder.</summary>
13	    public required string AdrSourceRoot { get; init; }
14	
15	    /// <summary>True when the ADR directory was set explicitly (via <c>--adrs</c>) rather than defaulted. ADRs are
16	    /// always optional, but an explicit-yet-missing directory is surfaced as a warning since it likely signals a typo.</summary>
17	    public required bool AdrSourceExplicit { get; init; }
18	
19	    public required string OutputRoot { get; init; }
20	
21	    /// <summary>The project's name, read from _bmad/config.toml's project_name — the site is branded with
22	    /// this rather than a generic tool name.</summary>
23	    public required string SiteTitle { get; init; }
24	
25	    /// <summary>When true (the default), a <c>README.md</c> found at the repo root is rendered into the site
26	    /// as a stylized page and surfaced from the home index. Disabled via <c>--no-readme</c>.</summary>
27	    public required bool IncludeReadme { get; init; }
28	
29	    /// <summary>When true (opt-in via <c>--deep-git</c>), the generator runs the heavier deep-git pass
30	    /// (change-coupling + hotspots) and renders its distinct dashboard panel. Off by default: the deep git
31	    /// process is never invoked when this is false, so baseline generation performance cannot regress. The
32	    /// flag is the FR-10 performance guarantee — the gate, not a timing test. [Story 3.2]</summary>
33	    public required bool DeepGitAnalytics { get; init; }
34	
35	    /// <summary>When true (opt-in via <c>--spa</c>), generation additionally emits the JSON + client-renderer (SPA)
36	    /// delivery form — a manifest, grouped content chunks, an entry shell, and the client script — ALONGSIDE the
37	    /// untouched static site (ADR 0006 Architecture B, Story 6.7). Off by default: with the flag off NO SPA files
38	    /// are written and the static output is byte-identical, so the golden gate is unaffected (AC #3/#5). Not
39	    /// <c>required</c> precisely so every existing <see cref="ForgeOptions"/> construction defaults to off. [Story 6.7]</summary>
40	    public bool EmitSpa { get; init; }
41	
42	    /// <summary>The code-link strategy (Story 7.1). When null/empty (the default), source citations resolve to
43	    /// in-portal code pages generated under <c>code/</c>. When set (via <c>--code-url</c>), the in-portal code-page
44	    /// phase is skipped entirely and citations resolve to <c>{CodeSourceBaseUrl}/&lt;repo-relative-path&gt;#L{n}</c>
45	    /// instead — the natural fit for a project whose docs are on GitHub Pages but whose code is on GitHub proper
46	    /// (which also supplies syntax highlighting for free). The <c>#L{n}</c> line anchor is identical in both modes,
47	    /// so 7.2's citation resolution differs only in the base. Not <c>required</c> so every existing
48	    /// <see cref="ForgeOptions"/> construction defaults to in-portal mode. [Story 7.1]</summary>
49	    public string? CodeSourceBaseUrl { get; init; }
50	
51	    public const string StylesheetName = "specscribe.css";
