94	    /// <summary>Resolves paths for a run. Explicit values win; anything omitted is derived from the repo root,
95	    /// which is either the parent of an explicit <paramref name="source"/> or found by walking up from
96	    /// <paramref name="startDirectory"/> (defaults to the current working directory) until a directory
97	    /// containing <c>_bmad-output</c> is found.</summary>
98	    public static ForgeOptions Resolve(
99	        string? source = null,
100	        string? adrs = null,
101	        string? output = null,
102	        string? projectName = null,
103	        string? startDirectory = null,
104	        bool includeReadme = true,
105	        bool deepGitAnalytics = false,
106	        bool emitSpa = false,
107	        string? codeSourceBaseUrl = null)
108	    {
109	        string repoRoot;
110	        string sourceRoot;
111	        if (source is { Length: > 0 })
112	        {
113	            sourceRoot = Path.GetFullPath(source);
114	            repoRoot = Path.GetDirectoryName(sourceRoot) ?? sourceRoot;
115	        }
116	        else
117	        {
118	            // Deliberately walks up from the cwd only — never the executable directory, which for an
119	            // installed global tool lives in the tool store under the user profile.
120	            var dir = new DirectoryInfo(startDirectory ?? Directory.GetCurrentDirectory());
121	            while (dir is not null && !Directory.Exists(Path.Combine(dir.FullName, SourceDirName)))
122	            {
123	                dir = dir.Parent;
124	            }
125	
126	            if (dir is null)
127	            {
128	                throw new DirectoryNotFoundException(
129	                    $"Could not locate a repo root (a directory containing '{SourceDirName}') at or above the " +
130	                    "current directory. Run from inside a BMad project, or pass --source to point at your artifacts.");
131	            }
132	
133	            repoRoot = dir.FullName;
134	            sourceRoot = Path.Combine(repoRoot, SourceDirName);
135	        }
136	
137	        return new ForgeOptions
138	        {
139	            RepoRoot = repoRoot,
140	            SourceRoot = sourceRoot,
141	            AdrSourceRoot = adrs is { Length: > 0 } ? Path.GetFullPath(adrs) : ResolveAdrSourceRoot(repoRoot),
142	            AdrSourceExplicit = adrs is { Length: > 0 },
143	            OutputRoot = output is { Length: > 0 } ? Path.GetFullPath(output) : Path.Combine(repoRoot, OutputDirName),
144	            SiteTitle = projectName is { Length: > 0 } ? projectName : ReadProjectName(repoRoot) ?? DefaultSiteTitle,
145	            IncludeReadme = includeReadme,
146	            DeepGitAnalytics = deepGitAnalytics,
147	            EmitSpa = emitSpa,
148	            CodeSourceBaseUrl = codeSourceBaseUrl is { Length: > 0 } ? codeSourceBaseUrl : null,
149	        };
150	    }
