152	    /// <summary>Resolves the implicit ADR root: the canonical <c>docs/adrs</c> whenever that directory exists
153	    /// (even if empty — today's behavior, untouched), otherwise the first
154	    /// <see cref="AdrFallbackProbeSubdirs"/> candidate holding at least one markdown file within one directory
155	    /// level. Resolved once here, at option time, so watch routing (<c>SiteGenerator.IsAdr</c> compares
156	    /// against this same path) and generation can never disagree about where ADRs live. A probe that finds
157	    /// nothing keeps the canonical (absent) default silently — ADRs are optional; only an EXPLICIT missing
158	    /// <c>--adrs</c> warns (see <see cref="AdrSourceExplicit"/>). [Story 4.2 Task 1]</summary>
159	    private static string ResolveAdrSourceRoot(string repoRoot)
160	    {
161	        var canonical = Path.Combine(repoRoot, "docs", "adrs");
162	        if (Directory.Exists(canonical))
163	        {
164	            return canonical;
165	        }
166	
167	        foreach (var subdir in AdrFallbackProbeSubdirs)
168	        {
169	            var candidate = Path.Combine(repoRoot, subdir);
170	            if (HasMarkdownWithinOneLevel(candidate))
171	            {
172	                return candidate;
173	            }
174	        }
175	
176	        return canonical;
177	    }
