192	                .Concat(Directory.EnumerateDirectories(dir)
193	                    .SelectMany(d => Directory.EnumerateFiles(d, "*.md", SearchOption.TopDirectoryOnly)))
194	                .Any(p => !PathUtil.IsIgnoredSourceFile(p)
195	                    && !string.Equals(Path.GetFileName(p), "README.md", StringComparison.OrdinalIgnoreCase));
196	        }
