753	        var repoFull = Path.GetFullPath(_options.RepoRoot);
754	        var sourceFull = Path.GetFullPath(_options.SourceRoot);
755	        var referenced = new SortedSet<string>(StringComparer.OrdinalIgnoreCase);
756	
757	        foreach (var file in sourceFiles)
758	        {
759	            string raw;
760	            string dir;
761	            try
762	            {
763	                dir = Path.GetDirectoryName(Path.GetFullPath(file)) ?? _options.SourceRoot;
764	                raw = MarkdownConverter.ReadAllTextShared(file);
765	            }
766	            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
767	            {
768	                // Non-fatal: an artifact we can't read simply contributes no citations.
769	                continue;
770	            }
771	
772	            var citingRelative = PathUtil.NormalizeSlashes(ToSourceRelative(file));
773	            var citingTitle = ExtractArtifactTitle(raw, citingRelative);
774	
775	            foreach (var citation in CodeReferenceScanner.ExtractTargets(raw))
776	            {
777	                if (!CodeReferenceScanner.TryResolveCitation(citation, dir, repoFull, sourceFull, out var repoRel))
