780	                }
781	                referenced.Add(repoRel);
782	
783	                // Reverse map: one entry per citing artifact per referenced file, deduped so an artifact that cites
784	                // the same file twice lists once. Order is deterministic (source-file iteration is sorted upstream).
785	                var list = _codeReverseMap.TryGetValue(repoRel, out var existing)
