198	    public void GenerateAll_GoldenContentFingerprint_IsStableAfterNormalizingVolatileTokens()
199	    {
200	        // AC #1's real guarantee is byte-for-byte-unchanged RENDERED OUTPUT, not merely a matching file set:
201	        // GoldenOutputInventory (above) pins the page SET, so a silent CONTENT drift that keeps filenames
202	        // stable — risk center #2, the exact failure the manual implementation-time byte-diff guarded once but
203	        // the suite did not — would sail through it. This pins the CONTENT: a SHA-256 over every output file,
204	        // after neutralizing the only volatile tokens (the wall-clock footer, the ?v=<ModuleVersionId> asset
205	        // cache-bust, CRLF, and the build-derived product version) — the same normalizations that diff used
206	        // (memory: golden-diff-normalization-gotchas). Regenerate the constant ONLY as a deliberate, reviewed
207	        // decision; an unexpected flip is a rendering regression. [Story 4.1 review]
208	        var gen = new SiteGenerator(Options());
209	        Assert.DoesNotContain(gen.GenerateAll(), e => e.Outcome == GenerationOutcome.Error);
210	
211	        var fingerprint = FingerprintTree(Site);
212	
213	        // Regenerated for Story 7.5: adds .commit-detail styling to specscribe.css (the per-commit detail page +
214	        // day-page hash-link affordance). The output FILE SET is unchanged for this non-deep-git fixture (commit/
215	        // pages are --deep-git-gated), so only the stylesheet bytes moved. [golden-diff-normalization-gotchas]
216	        const string expected = "1cd24db9269781f62bc07133aced56c9faa0a6743e1ac4653dbe68e651937868";
217	        Assert.True(
218	            expected == fingerprint,
219	            $"Rendered output content changed. If this was an intentional rendering change, update the constant "
