223	    // The footer date is now human-friendly + culture-invariant, e.g. "on July 10, 2026 at 5:14 PM".
224	    private static readonly Regex FooterClock = new(@"on [A-Za-z]+ \d{1,2}, \d{4} at \d{1,2}:\d{2} [AP]M", RegexOptions.Compiled);
225	    private static readonly Regex AssetCacheBust = new(@"\?v=[0-9a-fA-F]+", RegexOptions.Compiled);
226	    private static readonly Regex SubtitleVersion = new(@"SpecScribe v[^<]+", RegexOptions.Compiled);
227	    private static readonly Regex VersionRow = new(@"(<dt>Version</dt><dd>)[^<]*(</dd>)", RegexOptions.Compiled);
228	    // The About page's dynamic build identifier (build date · short commit hash) varies per build/commit.
229	    private static readonly Regex BuildRow = new(@"(<dt>Build</dt><dd>)[^<]*(</dd>)", RegexOptions.Compiled);
230	
231	    /// <summary>SHA-256 over every output file's normalized content (path-prefixed, ordinal-sorted), so ANY
232	    /// rendered-byte change flips one hash. Normalizes only per-run/per-build/per-machine noise, never artifact
233	    /// content — so the constant is portable across machines and CI, not pinned to this box.</summary>
234	    private string FingerprintTree(string root)
235	    {
236	        var sb = new StringBuilder();
237	        foreach (var rel in Directory.EnumerateFiles(root, "*", SearchOption.AllDirectories)
238	            .Select(p => PathUtil.NormalizeSlashes(Path.GetRelativePath(root, p)))
239	            .OrderBy(p => p, StringComparer.Ordinal))
240	        {
241	            sb.Append(rel).Append('\n')
242	              .Append(NormalizeVolatile(File.ReadAllText(Path.Combine(root, rel)))).Append("\n�\n");
243	        }
244	        return Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(sb.ToString()))).ToLowerInvariant();
245	    }
246	
247	    private string NormalizeVolatile(string content)
248	    {
249	        content = content.Replace("\r\n", "\n");
250	        // The diagnostics page prints the ABSOLUTE repo root (a random per-run temp dir, and machine-specific);
251	        // fold every form of the fixture root to a placeholder so the golden pins rendered content, not the box.
252	        content = content.Replace(PathUtil.NormalizeSlashes(_root), "<root>").Replace(_root, "<root>");
253	        content = FooterClock.Replace(content, "on <ts>");
254	        content = AssetCacheBust.Replace(content, "?v=<ver>");
255	        content = SubtitleVersion.Replace(content, "SpecScribe v<ver>");
256	        content = VersionRow.Replace(content, "$1<ver>$2");
257	        content = BuildRow.Replace(content, "$1<build>$2");
258	        return content;
259	    }
