  const aside = document.querySelector('.code-aside');
  const src = document.querySelector('.code-source-section');
  const list = document.querySelector('.ref-list');
  const ghIcon = document.querySelector('.code-external-link svg.host-icon');
  const extLink = document.querySelector('.code-external-link');
  const asideRect = aside?.getBoundingClientRect();
  const srcRect = src?.getBoundingClientRect();
  const pageCS = page ? getComputedStyle(page) : {};
  const listRect = list?.getBoundingClientRect();
  return {
    pageMaxWidth: pageCS.maxWidth,
    pagePadLeft: pageCS.paddingLeft,
    gridCols: layout ? getComputedStyle(layout).gridTemplateColumns : 'NONE',
    asideSticky: aside ? getComputedStyle(aside).position : 'NONE',
    // graph left of code (side by side)?
    sideBySide: asideRect && srcRect ? (asideRect.right <= srcRect.left + 5 && Math.abs(asideRect.top - srcRect.top) < 60) : null,
    listVisiblySmall: listRect ? (listRect.width <= 2 && listRect.height <= 2) : 'NO LIST',
    githubIconPresent: !!ghIcon,
    extLinkText: extLink?.textContent.trim(),
  };
})();"
}

