cd "C:/Users/MattE/AppData/Local/Temp/claude/C--Dev-SpecScribe/c5c56d80-11b8-4a3d-a418-ff16197365c1/scratchpad" && cat > assemble.js <<'EOF'
const fs = require('fs');
const path = require('path');
const root = path.join('prism-vendor','node_modules','prismjs');
const comps = JSON.parse(fs.readFileSync(path.join(root,'components.json'),'utf8')).languages;

// Curated language set for a general code-documentation tool.
const wanted = ['markup','css','clike','javascript','typescript','jsx','tsx','markup-templating',
  'csharp','php','json','json5','yaml','toml','bash','python','go','rust','sql','markdown',
  'java','kotlin','c','cpp','ruby','powershell','docker','ini','regex','diff','graphql'];

const seen = new Set();
const order = [];
function add(id){
  if (id === 'meta' || seen.has(id)) return;
  const meta = comps[id];
  if (!meta) { console.error('MISSING lang', id); return; }
  let req = meta.require || [];
  if (typeof req === 'string') req = [req];
  req.forEach(add);
  // also handle "modify"/"optional" deps loosely: none needed here
  seen.add(id);
  order.push(id);
}
wanted.forEach(add);

const parts = [];
// core first
parts.push(fs.readFileSync(path.join(root,'components','prism-core.min.js'),'utf8'));
for (const id of order){
  const f = path.join(root,'components',`prism-${id}.min.js`);
  if (!fs.existsSync(f)){ console.error('no min for', id); continue; }
  parts.push(fs.readFileSync(f,'utf8'));
}
// keep-markup plugin LAST (needs core + languages registered)
parts.push(fs.readFileSync(path.join(root,'plugins','keep-markup','prism-keep-markup.min.js'),'utf8'));

const banner = '/*! PrismJS 1.30.0 (https://prismjs.com) — MIT. Vendored bundle: core + '+order.length+' languages + keep-markup. Regenerate via scratchpad/assemble.js. */\n';
// Prism auto-highlights on DOMContentLoaded by default (no manual invocation needed); keep-markup preserves our line spans.
const out = banner + parts.join('\n;\n');
fs.writeFileSync('prism.bundle.js', out);
console.log('languages ('+order.length+'):', order.join(', '));
console.log('bytes:', out.length);
EOF
node assemble.js
